import { useState, useEffect } from "react";

export default function Hero() {
  const IMG = "data:image/png;base64,";
  const [toggled, setToggled] = useState(false);
  const [sparkles, setSparkles] = useState([]);

  useEffect(() => {
    setSparkles(Array.from({ length: 20 }, (_, i) => ({
      id: i,
      left: Math.random() * 100,
      top: Math.random() * 85,
      size: Math.random() * 7 + 3,
      delay: Math.random() * 5,
      dur: Math.random() * 3 + 2,
    })));
  }, []);

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Rajdhani:wght@400;500;600&display=swap');
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        html, body { width: 100%; height: 100%; overflow-x: hidden; }

        @keyframes wordReveal {
          from { opacity: 0; transform: translateY(110%) skewY(4deg); }
          to   { opacity: 1; transform: translateY(0) skewY(0deg); }
        }
        @keyframes fadeUp {
          from { opacity: 0; transform: translateY(22px); }
          to   { opacity: 1; transform: translateY(0); }
        }
        @keyframes fadeIn { from { opacity:0; } to { opacity:1; } }
        @keyframes lineGrow {
          from { transform: scaleX(0); opacity:0; }
          to   { transform: scaleX(1); opacity:1; }
        }
        @keyframes scrollBob {
          0%,100% { transform: translateX(-50%) translateY(0);   opacity:1;   }
          50%      { transform: translateX(-50%) translateY(8px); opacity:0.2; }
        }
        @keyframes glassGlow {
          0%,100% { box-shadow: 0 0 0 0 rgba(255,255,255,0.25), inset 0 0 0 0 rgba(255,255,255,0.08); }
          50%      { box-shadow: 0 0 0 7px rgba(255,255,255,0.0), inset 0 0 0 1px rgba(255,255,255,0.15); }
        }
        @keyframes dotPulse {
          0%,100% { box-shadow: 0 0 0 0 rgba(126,248,168,0.5); }
          50%      { box-shadow: 0 0 0 6px rgba(126,248,168,0); }
        }
        @keyframes sparkleFloat {
          0%   { opacity:0; transform: scale(0) rotate(0deg); }
          30%  { opacity:1; transform: scale(1) rotate(45deg); }
          70%  { opacity:0.5; transform: scale(0.7) rotate(120deg) translateY(-12px); }
          100% { opacity:0; transform: scale(0) rotate(200deg) translateY(-24px); }
        }
        @keyframes shimmer {
          0%,100% { background-position: -300% center; }
          50%      { background-position: 300% center; }
        }
        @keyframes cloudDrift {
          0%,100% { transform: translateX(0px) scale(1); }
          50%      { transform: translateX(10px) scale(1.01); }
        }
        @keyframes labelSwap {
          from { opacity:0; transform:translateY(5px); }
          to   { opacity:1; transform:translateY(0); }
        }

        .hero-root {
          position:relative; width:100%; height:100vh;
          min-height: -webkit-fill-available; overflow:hidden;
          font-family: "Rajdhani", sans-serif;
          background: #07152a;
        }
        .hero-bg {
          position:absolute; inset:0;
          background-size:cover; background-position:center top;
          animation: cloudDrift 18s ease-in-out infinite;
          will-change: transform;
        }
        .hero-overlay-bottom {
          position:absolute; inset:0; pointer-events:none;
          background: linear-gradient(to top,
            rgba(3,10,28,0.88) 0%,
            rgba(3,10,28,0.60) 28%,
            rgba(3,10,28,0.22) 55%,
            transparent 100%
          );
        }
        .hero-overlay-left {
          position:absolute; inset:0; pointer-events:none;
          background: linear-gradient(to right,
            rgba(3,10,28,0.45) 0%,
            transparent 55%
          );
        }

        /* Sparkles */
        .sparkle {
          position:absolute; pointer-events:none;
          animation: sparkleFloat var(--dur) ease-in-out var(--delay) infinite;
        }
        .sparkle::before {
          content:"✦"; color:rgba(255,255,255,0.9);
          font-size:var(--size); display:block;
          filter: drop-shadow(0 0 4px rgba(180,220,255,0.8));
        }

        /* Badge */
        .avail-btn {
          display:inline-flex; align-items:center; gap:10px;
          padding:11px 26px 11px 18px;
          background: rgba(255,255,255,0.10);
          backdrop-filter: blur(16px);
          -webkit-backdrop-filter: blur(16px);
          border: 1.5px solid rgba(255,255,255,0.30);
          border-radius:100px; cursor:pointer; min-height:44px;
          animation: fadeUp 0.9s cubic-bezier(0.16,1,0.3,1) 150ms both,
                     glassGlow 3.5s ease 1.5s infinite;
          transition: background 0.3s, transform 0.18s;
          -webkit-tap-highlight-color: transparent; outline:none;
        }
        .avail-btn:hover { background:rgba(255,255,255,0.20); border-color:rgba(255,255,255,0.5); }
        .avail-btn:active { transform:scale(0.96); }

        .avail-dot {
          width:8px; height:8px; border-radius:50%;
          background:#7EF8A8; flex-shrink:0;
          animation: dotPulse 2s ease 0.5s infinite;
        }
        .avail-label {
          font-family:"Rajdhani",sans-serif;
          font-size:11.5px; font-weight:600;
          letter-spacing:0.2em; text-transform:uppercase;
          color:#fff;
          animation: labelSwap 0.28s ease both;
        }

        /* Headline */
        .hero-headline {
          font-family:"Bebas Neue",sans-serif;
          font-size: clamp(72px,8.4vw,132px);
          font-weight:400; line-height:0.94;
          letter-spacing:0.025em; color:#fff;
          text-shadow:
            0 2px 4px rgba(0,0,0,0.5),
            0 10px 40px rgba(0,0,0,0.4),
            0 0 100px rgba(80,160,255,0.15);
          -webkit-font-smoothing:antialiased;
        }
        .hl-line { display:block; overflow:hidden; }
        .hl-inner { display:block; }
        .hl-inner.a1 { animation: wordReveal 1.1s cubic-bezier(0.16,1,0.3,1) 350ms both; }
        .hl-inner.a2 { animation: wordReveal 1.1s cubic-bezier(0.16,1,0.3,1) 550ms both; }
        .hl-shimmer {
          background: linear-gradient(120deg, #fff 25%, #b8dfff 48%, #7ec8f7 55%, #fff 72%);
          background-size:400% auto;
          -webkit-background-clip:text; background-clip:text;
          -webkit-text-fill-color:transparent;
          animation: wordReveal 1.1s cubic-bezier(0.16,1,0.3,1) 550ms both,
                     shimmer 6s linear 2s infinite;
        }

        /* Tagline */
        .hero-divider {
          width:36px; height:1.5px;
          background:rgba(255,255,255,0.55);
          transform-origin:left; flex-shrink:0;
          animation: lineGrow 0.7s cubic-bezier(0.16,1,0.3,1) 900ms both;
        }
        .hero-sub {
          font-family:"Rajdhani",sans-serif;
          font-size:12px; font-weight:500;
          letter-spacing:0.12em; text-transform:uppercase;
          color:rgba(255,255,255,0.65);
          animation: fadeUp 0.7s cubic-bezier(0.16,1,0.3,1) 950ms both;
        }

        /* Scroll indicator */
        .scroll-wrap {
          position:absolute; bottom:44px; left:50%;
          transform:translateX(-50%);
          display:flex; flex-direction:column; align-items:center; gap:9px;
          animation: fadeIn 1s ease 1300ms both;
        }
        .scroll-label {
          font-family:"Rajdhani",sans-serif;
          font-size:10px; font-weight:500;
          letter-spacing:0.22em; text-transform:uppercase;
          color:rgba(255,255,255,0.38);
        }
        .mouse {
          position:relative; width:18px; height:28px;
          border:1.5px solid rgba(255,255,255,0.3); border-radius:9px;
        }
        .mouse-dot {
          position:absolute; top:5px; left:50%;
          width:2px; height:5px; background:rgba(255,255,255,0.55);
          border-radius:2px;
          animation: scrollBob 1.7s ease-in-out infinite;
        }

        /* Layout */
        .hero-content {
          position:absolute; bottom:0; left:0; right:0; z-index:10;
          padding-left:7.5%; padding-right:7.5%; padding-bottom:120px;
        }
        .hero-badge-wrap   { margin-bottom:46px; }
        .hero-tagline-wrap { display:flex; align-items:center; gap:18px; margin-top:40px; }

        @media (min-width:1440px) {
          .hero-content {
            max-width:1920px; margin:auto;
            padding-left:clamp(7.5%,calc((100vw - 1600px)/2 + 7.5%),14%);
            padding-right:clamp(7.5%,calc((100vw - 1600px)/2 + 7.5%),14%);
          }
        }
        @media (min-width:768px) and (max-width:1023px) {
          .hero-headline { font-size:10vw; }
          .hero-content  { padding-bottom:100px; }
        }
        @media (max-width:767px) {
          .hero-headline { font-size:14.5vw; line-height:0.96; }
          .hero-content  { padding-left:5.5%; padding-right:5.5%; padding-bottom:100px; }
          .hero-badge-wrap   { margin-bottom:24px; }
          .hero-tagline-wrap { margin-top:20px; gap:12px; }
          .scroll-wrap       { bottom:90px; }
        }
        @media (max-width:359px) {
          .hero-headline { font-size:15vw; }
          .scroll-wrap   { bottom:82px; }
        }
        @supports (padding: env(safe-area-inset-bottom)) {
          .scroll-wrap { bottom:calc(44px + env(safe-area-inset-bottom,0px)); }
          @media (max-width:767px) {
            .scroll-wrap { bottom:calc(90px + env(safe-area-inset-bottom,0px)); }
          }
        }
        @media (max-width:900px) and (max-height:500px) and (orientation:landscape) {
          .hero-headline { font-size:8vw; }
          .hero-content  { padding-bottom:60px; }
          .scroll-wrap   { display:none; }
        }
      `}</style>

      <div className="hero-root">
        <div className="hero-bg" style={{ backgroundImage: `url(${IMG})` }} />
        <div className="hero-overlay-bottom" />
        <div className="hero-overlay-left" />

        {sparkles.map(s => (
          <div key={s.id} className="sparkle" style={{
            left: `${s.left}%`, top: `${s.top}%`,
            "--size": `${s.size}px`,
            "--delay": `${s.delay}s`,
            "--dur": `${s.dur}s`,
          }} />
        ))}

        <div className="hero-content">
          <div className="hero-badge-wrap">
            <button
              className="avail-btn"
              onClick={() => setToggled(p => !p)}
              aria-label={toggled ? "Discover the Craft" : "Available for Work"}
            >
              <span className="avail-dot" />
              <span className="avail-label" key={toggled ? "craft" : "avail"}>
                {toggled ? "Discover the Craft" : "Available for Work"}
              </span>
            </button>
          </div>

          <h1 className="hero-headline">
            <span className="hl-line">
              <span className="hl-inner a1">Exceptional Design</span>
            </span>
            <span className="hl-line" style={{ marginTop: "0.04em" }}>
              <span className="hl-inner a2 hl-shimmer">Needs No Explanation</span>
            </span>
          </h1>

          <div className="hero-tagline-wrap">
            <div className="hero-divider" />
            <span className="hero-sub">Craft · Clarity · Confidence</span>
          </div>
        </div>

        <div className="scroll-wrap">
          <div className="mouse"><div className="mouse-dot" /></div>
          <span className="scroll-label">Scroll</span>
        </div>
      </div>
    </>
  );
}